      styles: ["\n\n\n.contact-hero[_ngcontent-%COMP%] {\n  padding: var(--space-3xl) 0 var(--space-xl);\n  position: relative;\n}\n\n.contact-hero[_ngcontent-%COMP%]::before {\n  content: '';\n  position: absolute;\n  top: 0; left: 50%; transform: translateX(-50%);\n  width: 600px; height: 300px;\n  background: radial-gradient(ellipse, rgba(212,168,83,0.06) 0%, transparent 70%);\n  pointer-events: none;\n}\n\n.contact-title[_ngcontent-%COMP%] {\n  font-size: clamp(2.2rem, 4vw, 3.5rem);\n  font-weight: 700;\n  letter-spacing: -1.5px;\n  line-height: 1.15;\n  margin: 16px 0 20px;\n}\n\n.accent-italic[_ngcontent-%COMP%] { font-style: italic; color: var(--accent); font-weight: 400; }\n\n.contact-subtitle[_ngcontent-%COMP%] {\n  max-width: 500px;\n  font-size: 1rem;\n  color: var(--text-secondary);\n  line-height: 1.8;\n}\n\n\n\n.contact-layout[_ngcontent-%COMP%] {\n  display: grid;\n  grid-template-columns: 1fr 1.3fr;\n  gap: var(--space-2xl);\n  padding-bottom: var(--space-3xl);\n  align-items: start;\n}\n\n\n\n.contact-info-col[_ngcontent-%COMP%] {\n  display: flex;\n  flex-direction: column;\n  gap: 28px;\n  position: sticky;\n  top: 104px;\n}\n\n.info-cards[_ngcontent-%COMP%] {\n  display: flex;\n  flex-direction: column;\n  gap: 12px;\n}\n\n.info-card[_ngcontent-%COMP%] {\n  display: flex;\n  align-items: center;\n  gap: 16px;\n  padding: 16px 20px;\n  background: var(--bg-card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-md);\n  transition: var(--transition-fast);\n}\n\n.info-card[_ngcontent-%COMP%]:hover {\n  border-color: var(--border-hover);\n  background: var(--bg-hover);\n}\n\n.info-icon[_ngcontent-%COMP%] { font-size: 1.4rem; flex-shrink: 0; }\n\n.info-label[_ngcontent-%COMP%] {\n  font-size: 0.72rem;\n  text-transform: uppercase;\n  letter-spacing: 1px;\n  color: var(--text-muted);\n  font-weight: 600;\n  margin-bottom: 2px;\n}\n\n.info-value[_ngcontent-%COMP%] {\n  font-size: 0.9rem;\n  font-weight: 600;\n  color: var(--text-primary);\n}\n\n\n\n.faq-heading[_ngcontent-%COMP%] {\n  font-family: var(--font-display);\n  font-size: 1.1rem;\n  color: var(--text-primary);\n  margin-bottom: 12px;\n}\n\n.faq-list[_ngcontent-%COMP%] {\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n}\n\n.faq-item[_ngcontent-%COMP%] {\n  background: var(--bg-card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-md);\n  overflow: hidden;\n  transition: border-color 0.2s;\n}\n\n.faq-item.open[_ngcontent-%COMP%] { border-color: var(--border-hover); }\n\n.faq-question[_ngcontent-%COMP%] {\n  width: 100%;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 14px 16px;\n  background: none;\n  border: none;\n  font-family: var(--font-body);\n  font-size: 0.875rem;\n  font-weight: 600;\n  color: var(--text-primary);\n  cursor: pointer;\n  text-align: left;\n  gap: 12px;\n  transition: background 0.2s;\n}\n\n.faq-question[_ngcontent-%COMP%]:hover { background: var(--bg-hover); }\n\n.faq-arrow[_ngcontent-%COMP%] {\n  font-size: 0.6rem;\n  color: var(--accent);\n  flex-shrink: 0;\n  transition: transform 0.2s;\n}\n\n.faq-answer[_ngcontent-%COMP%] {\n  max-height: 0;\n  overflow: hidden;\n  transition: max-height 0.3s ease;\n}\n\n.faq-item.open[_ngcontent-%COMP%]   .faq-answer[_ngcontent-%COMP%] {\n  max-height: 200px;\n}\n\n.faq-answer[_ngcontent-%COMP%]   p[_ngcontent-%COMP%] {\n  padding: 0 16px 16px;\n  font-size: 0.825rem;\n  color: var(--text-muted);\n  line-height: 1.7;\n}\n\n\n\n.contact-form-col[_ngcontent-%COMP%] { }\n\n.contact-form-card[_ngcontent-%COMP%] {\n  background: var(--bg-card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-lg);\n  padding: 36px;\n}\n\n.form-card-title[_ngcontent-%COMP%] {\n  font-family: var(--font-display);\n  font-size: 1.4rem;\n  margin-bottom: 24px;\n  padding-bottom: 20px;\n  border-bottom: 1px solid var(--border);\n}\n\n.contact-form[_ngcontent-%COMP%] {\n  display: flex;\n  flex-direction: column;\n  gap: 4px;\n}\n\n.form-row[_ngcontent-%COMP%] {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 16px;\n}\n\n.btn-send[_ngcontent-%COMP%] {\n  height: 50px;\n  font-size: 0.95rem;\n  font-weight: 600;\n  justify-content: center;\n  margin-top: 8px;\n  width: 100%;\n}\n\n\n\n.success-card[_ngcontent-%COMP%] {\n  background: var(--bg-card);\n  border: 1px solid rgba(39,174,96,0.3);\n  border-radius: var(--radius-lg);\n  padding: 64px 36px;\n  text-align: center;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 16px;\n}\n\n.success-icon[_ngcontent-%COMP%] {\n  width: 64px;\n  height: 64px;\n  border-radius: 50%;\n  background: rgba(39,174,96,0.12);\n  border: 2px solid rgba(39,174,96,0.4);\n  color: #2ecc71;\n  font-size: 1.5rem;\n  font-weight: 700;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.success-card[_ngcontent-%COMP%]   h3[_ngcontent-%COMP%] {\n  font-family: var(--font-display);\n  font-size: 1.5rem;\n}\n\n.success-card[_ngcontent-%COMP%]   p[_ngcontent-%COMP%] {\n  font-size: 0.9rem;\n  color: var(--text-muted);\n  max-width: 320px;\n}\n\n\n\n@media (max-width: 900px) {\n  .contact-layout[_ngcontent-%COMP%] { grid-template-columns: 1fr; }\n  .contact-info-col[_ngcontent-%COMP%] { position: static; }\n  .form-row[_ngcontent-%COMP%] { grid-template-columns: 1fr; }\n}\n\n@media (max-width: 480px) {\n  .contact-form-card[_ngcontent-%COMP%] { padding: 24px 20px; }\n}\n\n\n\n.sending-spinner[_ngcontent-%COMP%] {\n  display: inline-block;\n  width: 14px;\n  height: 14px;\n  border: 2px solid rgba(15,15,15,0.3);\n  border-top-color: var(--bg-primary);\n  border-radius: 50%;\n  animation: _ngcontent-%COMP%_spin 0.7s linear infinite;\n  margin-right: 6px;\n  vertical-align: middle;\n}\n\n@keyframes _ngcontent-%COMP%_spin { to { transform: rotate(360deg); } }\n\n\n\n.contact-prefill-banner[_ngcontent-%COMP%] {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  padding: 9px 14px;\n  background: rgba(39,174,96,0.08);\n  border: 1px solid rgba(39,174,96,0.25);\n  border-radius: var(--radius-md);\n  font-size: 0.8rem;\n  color: #2ecc71;\n  font-weight: 500;\n  margin-bottom: 4px;\n}\n\n.prefill-icon[_ngcontent-%COMP%] { font-size: 0.9rem; flex-shrink: 0; }\n\n\n\n.form-control.prefilled[_ngcontent-%COMP%] {\n  background: var(--bg-primary);\n  border-color: rgba(39,174,96,0.3);\n  color: var(--text-secondary);\n  opacity: 0.85;\n}\n\n*[_ngcontent-%COMP%]   \u2500\u2500[_ngcontent-%COMP%]   Become-an-Author[_ngcontent-%COMP%]   banner[_ngcontent-%COMP%]   \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500[_ngcontent-%COMP%]   */\n.become-author-banner[_ngcontent-%COMP%] {\n  display: flex;\n  align-items: flex-start;\n  gap: 16px;\n  padding: 20px 22px;\n  background: linear-gradient(135deg,\n    rgba(45, 106, 79, 0.08) 0%,\n    rgba(45, 106, 79, 0.04) 100%);\n  border: 1.5px solid rgba(45, 106, 79, 0.35);\n  border-left: 5px solid var(--accent);\n  border-radius: var(--radius-lg);\n  margin-bottom: 20px;\n}\n \n.bab-icon[_ngcontent-%COMP%] {\n  font-size: 1.8rem;\n  flex-shrink: 0;\n  line-height: 1;\n  margin-top: 2px;\n}\n \n.bab-body[_ngcontent-%COMP%] { flex: 1; }\n \n.bab-title[_ngcontent-%COMP%] {\n  font-family: var(--font-display);\n  font-size: 1rem;\n  font-weight: 700;\n  color: var(--accent);\n  margin: 0 0 6px;\n}\n \n.bab-desc[_ngcontent-%COMP%] {\n  font-size: 0.875rem;\n  color: var(--text-secondary);\n  line-height: 1.7;\n  margin: 0;\n}\n/*# sourceMappingURL=data:application/json;charset=utf-8;base64, */"]
